ON CONFLICT ((LOWER(publisher_name))) DO UPDATE SET
  contact_email = COALESCE(EXCLUDED.contact_email, publishers.contact_email),
  contact_name = COALESCE(EXCLUDED.contact_name, publishers.contact_name),
  affiliate_network = COALESCE(EXCLUDED.affiliate_network, publishers.affiliate_network),
  affiliate_type = COALESCE(EXCLUDED.affiliate_type, publishers.affiliate_type),
  category = COALESCE(EXCLUDED.category, publishers.category),
  historical_gmv = GREATEST(COALESCE(EXCLUDED.historical_gmv, 0), COALESCE(publishers.historical_gmv, 0)),
  historical_transactions = GREATEST(COALESCE(EXCLUDED.historical_transactions, 0), COALESCE(publishers.historical_transactions, 0)),
  historical_clicks = GREATEST(COALESCE(EXCLUDED.historical_clicks, 0), COALESCE(publishers.historical_clicks, 0)),
  historical_roi = CASE WHEN COALESCE(EXCLUDED.historical_roi, 0) > 0 THEN EXCLUDED.historical_roi ELSE publishers.historical_roi END,
  historical_cvr = CASE WHEN COALESCE(EXCLUDED.historical_cvr, 0) > 0 THEN EXCLUDED.historical_cvr ELSE publishers.historical_cvr END,
  gmv_history_source = COALESCE(EXCLUDED.gmv_history_source, publishers.gmv_history_source),
  summary_note = COALESCE(EXCLUDED.summary_note, publishers.summary_note),
  updated_at = NOW();
